INSERT INTO properties (reference, title, title_nl, title_en, description, description_nl, description_en, price, slug_fr, slug_nl, slug_en, surface, rooms, bedrooms, bathrooms, property_type, condition, status, location_city, location_region, location_address, features, energy_rating, published)
VALUES
('SEC-1941', 'Pilar de la Horadada : beaux appartments en 2 chambres', '', '', 'Située dans un quartier central de Pilar de la Horadada, cette nouvelle résidence bénéficie d?un emplacement idéal, à proximité de toutes les commodités nécessaires, telles que des supermarchés et divers services. Sa proximité avec les plages en fait un choix parfait pour vos moments de détente et vos escapades estivales. Ce complexe résidentiel se compose de 12 appartements modernes, tous de plain-pied. Les appartements 2 chambres et 2 salles de bains allient élégance et fonctionnalité. Chaque appartement dispose d''une cuisine entièrement équipée avec des appareils électroménagers modernes. Les salles de bains sont équipées d''un meuble avec lavabo et éclairage intégré. De plus, chaque propriété est préinstallée pour la climatisation, et les appartements du dernier étage bénéficient d?un superbe solarium. Vous pourrez également profiter d''une piscine commune, idéale pour se détendre et passer de bons moments en famille ou entre amis. L''emplacement est exceptionnel, à seulement 5 minutes des plages de sable fin et du prestigieux parcours de golf 18 trous Lo Romero, un véritable atout pour les amateurs de loisirs en plein air. Pilar de la Horadada, un village typiquement espagnol, se trouve au sud de la Costa Blanca. La rue principale regorge de supermarchés, boutiques, restaurants et bars, ainsi que de charmantes places où vous pourrez vous détendre. Les plages de Torre de la Horadada et de Mil Palmeras, avec leur longue promenade en sable, sont accessibles en quelques minutes. Les aéroports de Corvera (Murcia) et d''Alicante se trouvent à 40 et 55 minutes, respectivement, facilitant vos déplacements. Prix: à partir de 239.900 ? hors frais Fin des travaux: décembre 2025', '', '', 239900, 'pilar-de-la-horadada-beaux-appartments-en-2-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1737', 'Condado de Alhama: belles villas 3 chambres avec piscine privée', '', '', 'Ces belles villas modernes sont situées à Condado de Alhama (Murice), dans un complexe de luxe, avec des zones sportives et entourées par la nature, tous les services et plusieurs terrains de golf. Les plages de Mazarrón se trouvent à 25 minutes en voiture. Les villas disposent, au rez-de-chaussée, de 3 chambres, 2 salles de bains, d''une cuisine équipée ouverte donnant sur le vaste séjour avec baies vitrées vers la terrasse avec piscine privée. A l''étage: solarium de 105 m² Place de parking sur la parcelle Prix: de 305.900 ? à 381.700 ? hors frais Électroménagers inclus Fin des travaux: août 2026', '', '', 305900, 'condado-de-alhama-belles-villas-3-chambres-avec-piscine-privee', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1772', 'Benijofar: belles villas 3 chambres de style méditérranéen', 'Los Montesinos: prachtige villa''s met 3 slaapkamers in mediterrane stijl', '', 'Ces belles villas de style méditerranéen sont situées à Bénijofar, à proximité de toutes les facilités telles que supermarché, magasins, restaurants, pharmacie,... L''aéroport d''Alicante se trouve à 30 minutes en voiture et les plages de Guardamar se trouvent à 10 minutes. Les villas disposent d''une cuisine ouverte donnant sur le vaste séjour avec portes-fenêtres vers la terrasse et la piscine de 20 m². 3 chambres, 2 salles de bains et une remise. Place de parking sur la parcelle. Au 1er étage: solarium avec vue dégagée sur les environs Sous-sol Parcelles de 279 m² Prix: 529.900 ? hors frais Fin des travaux: mars 2025', 'Deze prachtige villa''s in mediterrane stijl zijn gelegen in Bénijofar, dichtbij alle faciliteiten zoals supermarkt, winkels, restaurants, apotheek,... De luchthaven van Alicante ligt op 30 minuten rijden en de stranden van Guardamar liggen op 10 minuten afstand. De villa''s hebben een open keuken aansluitend op de grote woonkamer met openslaande deuren naar het terras en het zwembad van 20 m². 3 slaapkamers, 2 badkamers en een berging. Parkeerplaats op het perceel. Op de eerste verdieping: solarium met open uitzicht over de omgeving Percelen van 279 m². Prijs: van ? 529.900 tot ? 439.900 exclusief kosten Oplevering: maart 2025', '', 529900, 'benijofar-belles-villas-3-chambres-de-style-mediterraneen', 'los-montesinos-prachtige-villa-s-met-3-slaapkamers-in-mediterrane-stijl', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1748', 'Torre Pacheco: beaux appartements 2 chambres dans un resort avec lagon artificiel', 'Torre Pacheco: prachtige appartementen met 2 slaapkamers in een resort met een kunstmatig meer', '', 'Ce nouveau concept révolutionne le concept d''urbanisation ! Le resort est construit autour d''un lagon artificiel de 16 000 m², entouré de plages de sable blanc et de palmiers, et de vastes parcs sur une superficie de plus de 120 000 m². Deux îles ont été construites sur le lac, l''une avec son propre bar et restaurant. Situé non loin de la mer, il conjugue tous les plaisirs pour les futurs propriétaires: le calme, les activités sur site et la vie balnéaire toute proche avec ses restaurants, cafés et commerces. Dans les magnifiques jardins, vous pourrez contempler la nature luxuriante, jouer au golf, à la pétanque ou simplement vous reposer pendant que les enfants s''amuseront à la plaine de jeux. Chaque bâtiment compte 7 appartements répartis sur 4 niveaux. Belle piscine commune avec jardin. Les appartements comptent 2 chambres et 2 salles de bains, ainsi qu''une place de parking et un débarras. Ils disposent tous d''une belle terrasse avec vue sur le lagon. Prix: à partir de 287.900 ? hors frais', 'Het resort is gebouwd rond een kunstmatige lagune van 16.000 m², omgeven door witte zandstranden en palmbomenen, en uitgestrekte parken op een oppervlakte van meer dan 120.000 m². In het meer zijn 2 verschillende eilanden aangelegd waarvan een met eigen bar en restaurant. Het resort is gelegen niet ver van de zee en combineert alle geneugten voor toekomstige eigenaren: rust, activiteiten ter plaatse en het nabijgelegen leven aan zee met zijn restaurants, cafés en winkels. In de prachtige tuinen kunt u de weelderige natuur aanschouwen, golfen, jeu de boules spelen of gewoon uitrusten terwijl de kinderen zich vermaken in de speeltuin. Elk gebouw heeft 7 appartementen, verdeeld over 4 niveaus. De residentie heeft ook een prachtig gemeenschappelijk zwembad met tuin. De appartementen hebben 2 slaapkamers en 2 badkamers, evenals een parkeerplaats en een berging. Ze hebben allemaal een mooi terras met uitzicht op de lagune. Prijs: vanaf ? 287.900 exclusief kosten', '', 287900, 'torre-pacheco-beaux-appartements-2-chambres-dans-un-resort-avec-lagon-artificiel', 'torre-pacheco-prachtige-appartementen-met-2-slaapkamers-in-een-resort-met-een-kunstmatig-meer', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1749', 'Torre Pacheco: superbes appartements 3 chambres dans un resort avec lagon artificiel', 'Torre Pacheco: prachtige appartementen met 3 slaapkamers in een resort met een kunstmatig meer', '', 'Ce nouveau concept révolutionne le concept d''urbanisation ! Le resort est construit autour d''un lagon artificiel de 16 000 m², entouré de plages de sable blanc et de palmiers, et de vastes parcs sur une superficie de plus de 120 000 m². Deux îles ont été construites sur le lac, l''une avec son propre bar et restaurant. Situé non loin de la mer, le resort conjugue tous les plaisirs pour les futurs propriétaires: le calme, les activités sur site et la vie balnéaire toute proche avec ses restaurants, cafés et commerces. Dans les magnifiques jardins, vous pourrez contempler la nature luxuriante, jouer au golf, à la pétanque ou simplement vous reposer pendant que les enfants s''amuseront à la plaine de jeux. Chaque bâtiment compte 7 appartements répartis sur 4 niveaux Belle piscine commune avec jardin. Les appartements 3 chambres sont situés au rez-de-chaussée ou au dernier étage. Les appartements comptent 3 chambres et 2 salles de bains, ainsi qu''une place de parking et un débarras. Ils disposent tous d''une belle terrasse avec vue sur le lagon. Prix: à partir de 369.900 ? hors frais', 'Het resort is gebouwd rond een kunstmatige lagune van 16.000 m², omgeven door witte zandstranden en palmbomenen, en uitgestrekte parken op een oppervlakte van meer dan 120.000 m². In het meer zijn 2 verschillende eilanden aangelegd waarvan een met eigen bar en restaurant. Het resort is gelegen niet ver van de zee en combineert alle geneugten voor toekomstige eigenaren: rust, activiteiten ter plaatse en het nabijgelegen leven aan zee met zijn restaurants, cafés en winkels. In de prachtige tuinen kunt u de weelderige natuur aanschouwen, golfen, jeu de boules spelen of gewoon uitrusten terwijl de kinderen zich vermaken in de speeltuin. Elk gebouw heeft 7 appartementen, verdeeld over 4 niveaus. De residentie heeft ook een prachtig gemeenschappelijk zwembad met tuin. De appartementen hebben 3 slaapkamers en 2 badkamers, evenals een parkeerplaats en een berging. Ze hebben allemaal een mooi terras met uitzicht op de lagune. Prijs: vanaf ? 369.900 exclusief kosten', '', 369900, 'torre-pacheco-superbes-appartements-3-chambres-dans-un-resort-avec-lagon-artificiel', 'torre-pacheco-prachtige-appartementen-met-3-slaapkamers-in-een-resort-met-een-kunstmatig-meer', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1750', 'Algorfa: superbe villa 3 chambres dans un magnifique golf', 'Algorfa: prachtige villa met 3 slaapkamers op een prachtige golfbaan', '', 'Ces superbes villas 3 chambres, alliant style traditionnel et modernité, sont situées au coeur de l''un des plus beaux golfs de la Costa Blanca, à 12 km des plages de Guardamar. Toutes les commodités (restaurants, bars, spa dans hôtel 5*,...) sont sur place et la petite ville d''Algorfa se trouve à seulement 2 km. Les villas disposent de 3 chambres, 2 salles de bains, d''une cuisine ouverte donnant sur un vaste séjour avec baies vitrées vers le jardin et la piscine privée. Climatisation, chauffage au sol dans les salles de bains, dressing dans la chambre principale et place de parking. Prix: De 535.000 ? à 545.000 ? hors frais Livraison: septembre 2023', 'Deze prachtige villa''s met 3 slaapkamers, een combinatie van traditionele stijl en moderniteit, zijn gelegen in het hart van een van de mooiste golfbanen van de Costa Blanca, op 12 km van de stranden van Guardamar. Alle voorzieningen (restaurants, bars, spa in een 5*-hotel, enz.) zijn ter plaatse en het stadje Algorfa ligt op slechts 2 km afstand. De villa''s hebben 3 slaapkamers, 2 badkamers, een open keuken die uitkomt op een grote woonkamer met glazen deuren naar de tuin en het privézwembad. Airconditioning, vloerverwarming in de badkamers, kleedkamer in de hoofdslaapkamer en parkeerplaats. Prijs: Van ?535.000 tot ?545.000 exclusief kosten Levering: september 2023', '', 535000, 'algorfa-superbe-villa-3-chambres-dans-un-magnifique-golf', 'algorfa-prachtige-villa-met-3-slaapkamers-op-een-prachtige-golfbaan', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1751', 'Algorfa: belles maisons jumelées en 3 chambres, au coeur d''un superbe parcours de golf', 'Algorfa: prachtige halfvrijstaande huizen met 3 slaapkamers, in het hart van een prachtige golfbaan', '', 'Ces belles maisons 3 chambres sont situées au coeur de l''un des plus beaux golfs de la Costa Blanca, à 12 km des plages de Guardamar. Toutes les commodités (restaurants, bars, spa dans hôtel 5*,...) sont sur place et la petite ville d''Algorfa se trouve à seulement 2 km. Au rez-de-chaussée: 2 chambres, 1 salle de bains, cuisine ouverte sur le living avec baies vitrées vers le jardin avec piscine privée. 1er étage: 1 chambre et 1 salle de bains, accès au vaste solarium Climatisation, chauffage au sol dans les salles de bains et place de parking. Prix: à partir de 449.000 ? hors frais', 'Deze prachtige huizen met 3 slaapkamers zijn gelegen in het hart van een van de mooiste golfbanen van de Costa Blanca, op 12 km van de stranden van Guardamar. Alle voorzieningen (restaurants, bars, spa in een 5*- hotel, enz.) zijn ter plaatse en het stadje Algorfa ligt op slechts 2 km afstand. Op de begane grond: 2 slaapkamers, 1 badkamer, open keuken naar de woonkamer met openslaande deuren naar de tuin met privé zwembad. 1ste verdieping: 1 slaapkamer en 1 badkamer, toegang tot het grote dakterras Airconditioning, vloerverwarming in de badkamers en parkeerplaats. Prijs: vanaf ? 449.000 exclusief kosten', '', 449000, 'algorfa-belles-maisons-jumelees-en-3-chambres-au-coeur-d-un-superbe-parcours-de-golf', 'algorfa-prachtige-halfvrijstaande-huizen-met-3-slaapkamers-in-het-hart-van-een-prachtige-golfbaan', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1753', 'Calasparra: superbes villas modernes en 3 chambres', 'Calasparra: prachtige moderne villa''s met 3 slaapkamers', '', 'Ces superbes villas sont situées dans un environnement naturel privilégié, entre 3 chaînes de montagnes. Dans la région, vous pourrez profiter du patrimoine historique, culturel, de la nature et de la gastronomie. L''aéroport de Murcia-Corvera est à 45 minutes et les plages de la Costa Calida à 1h00. Dans un environnement proche, accès à tous les services tels que restaurants, bars, installations sportives, supermarchés, magasins, points d''intérêt touristique très attractifs tels que le sanctuaire de Notre-Dame de l''Espérance et le sanctuaire de Vera Cruz (également ville sainte), Las Cuevas del Puerto, descente de la rivière Segura en kayak... Les villas, de plain-pied, sont construites sur des parcelles de 540 m² et disposent de 3 chambres, 2 salles de bains, d''une cuisine équipée ouverte donnant sur le living avec baies vitrées vers le jardin et la terrasse avec piscine privée. Prix: à partir de 335.000 ? hors frais Inclus dans le prix: - Piscine de 7m x 3.5m - Jardin avec pelouse artificielle et graviers blancs - Éclairage LED intérieur et extérieur - Prises TV dans toutes les chambres et fibre dans le salon - Cuisine équipée (lave-linge, four, taque vitrocéramique, hotte, lave-vaisselle, frigo, chauffe-eau de 150 L) - Place de parking', 'Deze prachtige villa''s zijn gelegen in een bevoorrechte natuurlijke omgeving, tussen 3 bergketens. In de regio kunt u genieten van historisch en cultureel erfgoed, natuur en gastronomie. De luchthaven van Murcia-Corvera ligt op 45 minuten afstand en de stranden van de Costa Calida op 1 uur rijden. In een nabije omgeving, toegang tot alle diensten zoals restaurants, bars, sportfaciliteiten, supermarkten, winkels, zeer aantrekkelijke toeristische bezienswaardigheden zoals het Heiligdom van Onze-Lieve-Vrouw van Hoop en het Heiligdom van Vera Cruz (ook heilige stad ), Las Cuevas del Puerto, kajakken op de rivier Segura... De gelijkvloerse villa''s zijn gebouwd op percelen van 540 m² en hebben 3 slaapkamers, 2 badkamers, een open ingerichte keuken die uitkomt op de woonkamer met schuifdeuren naar de tuin en het terras met privé zwembad. Prijs: vanaf ? 335.000 exclusief kosten In de prijs inbegrepen: - Zwembad van 7m x 3,5m - Tuin met kunstgras en wit grind - LED-verlichting binnen en buiten - Uitgeruste keuken (wasmachine, oven, keramische kookplaat, afzuigkap, vaatwasser, koelkast, boiler 150 L) - Parkeerplaats', '', 335000, 'calasparra-superbes-villas-modernes-en-3-chambres', 'calasparra-prachtige-moderne-villa-s-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1758', 'DERNIERES UNITES ! Busot: belles maisons en 3 chambres', 'Busot: mooie geschakelde woningen met 3 slaapkamers', '', 'Cette résidence est située à côté du petit village de Busot, au nord d''Alicante, à +/- 9 kms des belles plages d''El Campello. Vous pourrez jouir d''une vue magnifique sur la vallée de Cabeço d''Or, le village de Busot ou sur les montages d''Alicante. Au village, vous trouverez toutes les commodités nécessaires. Les maisons 3 chambres et 2 ou 3 salles de bains disposent, au rez-de-chaussée, d''une cuisine ouverte sur le living, d''une buanderie, d''une chambre et d''une salle de bains. Au 1er étage: 2 chambres, 1 salle de bains et accès à une terrasse. Jardin privatif et place de parking. Possibilité de construire sa piscine privée moyennant supplément. La résidence dispose d''une piscine commune. Prix: - Maison accolée, 3 chambres et 2 salles de bains : 355.000 ? hors frais - Toute équipée (meubles, déco, climatisation) - Maison individuelle, 3 chambres et 3 salles de bains : 409.000 ? hors frais KEY READY', 'Deze residentie is gesitueerd vlak naast het kleine dorpje Busot, ten noorden van Alicante, op ongeveer 9 km van de mooie stranden van El Campello. U kan er optimaal genieten van de uitstekende uitzichten over de vallei van Cabeço d''Or, het dorpje Busot of de bergen van Alicante. In het dorp vindt u alle nodige faciliteiten. De woningen met 3 slaapkamers en 2 badkamers hebben op de begane grond een open keuken naar de woonkamer, een wasruimte, een slaapkamer en een badkamer. Op de 1ste verdieping: 2 slaapkamers, 1 badkamer en toegang tot een terras. Eigen tuin en parkeerplaats. Mogelijkheid om tegen meerprijs een privézwembad te bouwen. De residentie beschikt over een gemeenschappelijk zwembad. Prijs: ?355.000 exclusief kosten. KEY READY', '', 355000, 'dernieres-unites-busot-belles-maisons-en-3-chambres', 'busot-mooie-geschakelde-woningen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1762', 'San Pedro del Pinatar: jolies maisons 3 chambres avec piscine privée', 'San Pedro del Pinatar: mooie huizen met 3 slaapkamers en privézwembad', '', 'Cette nouvelle résidence est idéalement située à San Pedro del Pinatar, à proximité des commerces et restaurants et non loin des plages. La résidence compte 18 maisons 3 chambres, chacune avec piscine privée, une terrasse, un solarium et une place de parking. Au rez-de-chaussée: cuisine fermée ou ouverte (au choix) sur le living avec portes-fenêtres vers la terrasse, une chambre et une salle de bains. 1er étage: 2 chambres et une salle de bains, accès à une terrasse 2ème étage: solarium Équipements: - Piscine privée avec éclairage LED et douche extérieure. - Cuisine entièrement meublée et équipée avec four et micro-ondes, lave-vaisselle, frigo, plaque vitrocéramique et hotte. - Éclairage LED : à l''intérieur de la maison (séjour, cuisine, couloirs et salles de bains), ainsi qu''à l''extérieur. - Stores motorisés dans le salon et la chambre principale. - Dressing dans la chambre principale, avec étagères, tiroirs, porte-pantalons et miroir. Prix: 369.900? hors frais Fin des travaux: novembre 2025', 'Deze nieuwe residentie is ideaal gelegen in San Pedro del Pinatar, dicht bij winkels en restaurants en niet ver van de stranden. De residentie heeft 18 huizen met 3 slaapkamers, elk met een privézwembad, een terras, een dakterras en een parkeerplaats. Op de begane grond: open keuken naar de woonkamer met openslaande deuren naar het terras, een slaapkamer en een badkamer. 1ste verdieping: 2 slaapkamers en een badkamer, toegang tot een terras 2de verdieping: dakterras - Privé zwembad met LED verlichting en douche. - Volledig ingerichte en uitgeruste keuken met oven, magnetron, vaatwasser, koelkast, keramische kookplaat en afzuigkap. - LED-verlichting: binnen (woonkamer, keuken, gangen en badkamers), maar ook buiten. - Gemotoriseerde zonwering in de woonkamer en in de hoofdslaapkamer - Kleedkamer in de hoofdslaapkamer, met planken, lades, broekenrek en spiegel. Prijs: ?369.900 exclusief kosten Oplevering: nov 2025', '', 369900, 'san-pedro-del-pinatar-jolies-maisons-3-chambres-avec-piscine-privee', 'san-pedro-del-pinatar-mooie-huizen-met-3-slaapkamers-en-privezwembad', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1879', 'Los Alcazares: beaux appartements 3 chambres sur un golf', '', '', 'Cette nouvelle résidence est située à La Serena Golf, Los Alcazares, à seulement 2 km des plages de la Mar Menor. Le complexe comptera au total 244 appartements 2 ou 3 chambres, répartis en 8 bâtiments, sur 3 niveaux. Les appartements du rez-de-chaussée ont une terrasse et un jardin, ceux du 1er étage jouissent d''une belle terrasse, et ceux du 2ème étage bénéficient d''une terrasse et d''un vaste solarium. Les appartements offrent des vues soit sur les zones communes, soit sur le parcours de golf. Les appartements 3 chambres disposent de 2 salles de bains, ainsi que d''une place de parking et d''une cave en sous-sol. Belle piscine commune avec jardins. Prix: à partir de 312.000 ? hors frais Fin des travaux bloc 5 : janvier 2027', '', '', 312000, 'los-alcazares-beaux-appartements-3-chambres-sur-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1763', 'Punta Prima: beaux appartements 2 chambres à proximité de toutes les commodités', 'Punta Prima: mooie appartementen met 2 slaapkamers dicht bij alle voorzieningen', '', 'Cette nouvelle résidence comptera 87 appartements 2 ou 3 chambres et 7 villas 4 chambres. Elle est idéalement située à Punta Prima, à proximité de nombreux restaurants, supermarchés, magasins et à seulement 1,5 km de la mer. Les appartements 2 chambres sont situés au 1er étage et jouissent d''un agréable solarium. Les parties communes comptent de vastes jardins communs, une belle piscine, une piscine pour enfants, une aire de jeux et un jacuzzi. Prix: à partir de 290.000 ? hors frais Remise des clés: entre mars et septembre 2024', 'In deze nieuwe residentie worden 87 appartementen met 2 of 3 slaapkamers en 7 villa''s met 4 slaapkamers gebouwd. Het is ideaal gelegen in Punta Prima, dicht bij talrijke restaurants, supermarkten, winkels en op slechts 1,5 km van de zee. De appartementen met 2 slaapkamers bevinden zich op de verdieping en hebben een aangenaam solarium. De gemeenschappelijke ruimtes hebben uitgebreide gemeenschappelijke tuinen, een prachtig zwembad, kinderbad, speeltuin en jacuzzi. Prijs: vanaf ? 290.000,- exclusief kosten Oplevering: tussen maart en september 2024', '', 290000, 'punta-prima-beaux-appartements-2-chambres-a-proximite-de-toutes-les-commodites', 'punta-prima-mooie-appartementen-met-2-slaapkamers-dicht-bij-alle-voorzieningen', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1787', 'Lomas de Cabo Roig: superbes appartements 2 chambres', 'Lomas de Cabo Roig: prachtige appartementen met 2 slaapkamers', '', 'Cette nouvelle résidence est située au calme à Lomas de Cabo Roig, à distance de marche de deux centres commerciaux avec nombreux restaurants, bars et magasins. La résidence comptera au total 24 appartements 2 ou 3 chambres. Les appartements comptent 2 chambres, 2 salles de bains et une belle terrasse. Les penthouses du dernier étage disposent également d''un solarium. Belle piscine commune avec pataugeoire, jacuzzi, fitness et zone de barbecue. Prix: à partir de 314.600 ? hors frais Penthouses: à partir de 460.000 ? hors frais Inclus: place de parking et remise, climatisation, électroménagers, chauffage au sol dans les salles de bains Fin des travaux: décembre 2024', 'Deze nieuwe residentie is rustig gelegen in Lomas de Cabo Roig, op wandelafstand van twee winkelcentra met een uitgebreid aanbod aan restaurants, bars en winkels. De residentie zal bestaan uit 24 appartementen met 2 of 3 slaapkamers. De appartementen hebben 2 slaapkamers, 2 badkamers en een mooi terras. De penthouses op de bovenste verdieping hebben ook een solarium. Prachtig gemeenschappelijk zwembad met kindergedeelte, jacuzzi, fitness en barbecue zone. Prijs: vanaf ? 314.600,- exclusief kosten Penthouses: vanaf ? 460.000 exclusief kosten Inbegrepen: parkeerplaats en berging, airconditioning, elektrische apparaten, vloerverwarming in de badkamers. Oplevering: december 2024', '', 314600, 'lomas-de-cabo-roig-superbes-appartements-2-chambres', 'lomas-de-cabo-roig-prachtige-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1852', 'Algorfa: belles villas 3 chambres sur un golf', '', '', 'Ces nouvelles villas sont situées sur le golf de La Finca, un superbe parcours 18 trous considéré comme l''un des meilleurs de la région. L''endroit est idéal pour les amoureux de la nature et pour les amateurs de sports et de loisirs. Outre le parcours de golf, le domaine propose des courts de tennis et de paddel, une supérette, et plusieurs restaurants. La nature environnante regorge également de nombreux sentiers de randonnées. Les belles plages de Guardamar sont à 10 minutes en voiture et l''aéroport d''Alicante à 30 minutes. Les villas 3 chambres sont construites sur des parcelles allant de 236 m² à 358 m² et disposent de 2 salles de bains, d''une cuisine équipée ouverte donnant sur le vaste séjour, ainsi que d''un solarium de 87 m². Parking sur la parcelle. Piscine privée en option. Prix: à partir de 377.000 ? hors frais Inclus: - électroménagers - climatisation Fin des travaux: juin 2025', '', '', 377000, 'algorfa-belles-villas-3-chambres-sur-un-golf', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1773', 'Pilar de la Horadada: superbes villas 3 chambres en 1ère ligne de golf', 'Pilar de la Horadada: prachtige villa''s met 3 slaapkamers op de eerste lijn aan de golf', '', 'Ces superbes villas 3 chambres sont situées en première ligne de golf, et jouissent de magnifiques vue sur le green et les environs. Le resort se trouve à 5 minutes en voiture de tous les types de commerces et de services. Les plages et le joli port de plaisance de Torre de la Horadada sont à 10 minutes. Les villas jouissent au rez-de-chaussée d''une cuisine ouverte sur un vaste living avec accès direct au jardin avec piscine privée et terrasse (partiellement couverte), d''une chambre avec salle de bains, d''un WC séparé et d''une buanderie. Au 1er étage: 2 chambres, chacune avec salle de bains et accès à une terrasse de 10 m² et solarium de 25 m². Prix: de 654.000 ? à 698.000 ? hors frais Fin des travaux: décembre 2023', 'Deze prachtige villa''s met 3 slaapkamers bevinden zich op de eerste lijn van de golfbaan en genieten van een prachtig uitzicht op de green en de groene omgeving. Het resort ligt op 5 minuten rijden van alle soorten winkels en diensten. De stranden en de mooie jachthaven van Torre de la Horadada liggen op 10 minuten afstand. De villa''s hebben op de begane grond een open keuken naar een grote woonkamer met directe toegang tot de tuin met privé zwembad en het deels overdekte terras, een slaapkamer met badkamer, een apart toilet en een wasruimte. Op de 1ste verdieping: 2 slaapkamers, elk met badkamer en toegang tot een terras van 10 m² , solarium van 25 m². Prijs: van ? 654.000 tot ? 698.000 exclusief kosten Oplevering: december 2023', '', 654000, 'pilar-de-la-horadada-superbes-villas-3-chambres-en-1ere-ligne-de-golf', 'pilar-de-la-horadada-prachtige-villa-s-met-3-slaapkamers-op-de-eerste-lijn-aan-de-golf', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1774', 'DERNIERE UNITE! Benimar (Rojales): superbes villas en 4 chambres', 'LAST UNIT! Benimar (Rojales): prachtige villa''s met 4 slaapkamers', '', 'Ces superbes villas modernes sont situées à proximité de Rojales et Benijofar, à 15 minutes des belles plages de Guardamar. L''aéroport d''Alicante se trouve à 35 minutes. Rojales offre de nombreuses commodités locales, notamment des magasins, des bars, des restaurants et des supermarchés. Pour les amateurs de golf, les parcours de championnat de Rojales et de La Marquesa à Ciudad Quesada ne sont qu''à cinq minutes. Ces luxueuses villas modernes ont été conçues avec beaucoup de lumière et d''espaces ouverts, avec un sous-sol, un garage, une piscine privée, des terrasses spacieuses et un jardin paysager pour profiter du climat méditerranéen tout au long de l''année. Les propriétés comprennent quatre chambres doubles (toutes avec placards), trois salles de bains, un WC séparé, une cuisine intégrée moderne entièrement équipée avec bar à petit-déjeuner et un salon/salle à manger ouvert, menant au jardin avec piscine privée et un espace extérieur couvert pour les repas. Garage et remise. Prix: 775.000 ? hors frais', 'Deze prachtige moderne villa''s zijn gelegen in de buurt van Rojales en Benijofar, op 15 minuten van de prachtige stranden van Guardamar. De luchthaven van Alicante ligt op 35 minuten afstand. In de nabije omgeving vindt u alle voorzieningen: winkels, restaurants, bars, apotheek,... De 12 villa''s zijn als volgt ingedeeld: Begane grond: open keuken naar de ruime woonkamer, apart toilet, berging. 1ste verdieping: een slaapkamer met badkamer, solarium van 28 m² -1: 3 slaapkamers, 2 badkamers, wasruimte, garage, kelder Zwembad min. 8,5m x 3m Prijs: ? 775.000 exclusief kosten', '', 775000, 'derniere-unite-benimar-rojales-superbes-villas-en-4-chambres', 'last-unit-benimar-rojales-prachtige-villa-s-met-4-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1777', 'Las Colinas: superbes villas 3 chambres dans un golf exceptionnel', 'Las Colinas: prachtige villa''s met 3 slaapkamers op een uitzonderlijke golfbaan', '', 'Ces superbes villas se situent dans le domaine du golf de Las Colinas, un des plus beaux greens d''Europe. Les finitions de très haut vol sauront vous séduire autant que le caractère exclusif de la résidence. Les vues époustouflantes sur le domaine sont un plus pour ceux qui veulent vivre dans un cadre unique. Les villas de plain-pied sont construites sur des parcelles allant de 1013 m² à 1117 m². Elles disposent de 3 chambres, 2 salles de bains, d''une cuisine ouverte sur un vaste et lumineux living avec baies vitrées vers la terrasse avec piscine privée, d''une buanderie et d''un WC séparé. Prix: à partir de 875.000 ? hors frais', 'Deze prachtige villa''s bevinden zich op de golfbaan Las Colinas, een van de mooiste greens van Europa. De zeer hoogwaardige afwerking zal u evenzeer verleiden als het exclusieve karakter van de woning. Het adembenemende uitzicht op het domein is een pluspunt voor wie in een uniek kader wil wonen. De gelijkvloerse villa''s worden gebouwd op percelen van 1013 m² tot 1117 m². Ze hebben 3 slaapkamers, 2 badkamers, een open keuken naar een grote en lichte woonkamer, met openslaande deuren naar het terras met privézwembad, een wasruimte en een apart toilet. Prijs: vanaf 875.000 ? exclusief kosten', '', 875000, 'las-colinas-superbes-villas-3-chambres-dans-un-golf-exceptionnel', 'las-colinas-prachtige-villa-s-met-3-slaapkamers-op-een-uitzonderlijke-golfbaan', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1778', 'Torrevieja: superbes appartements 2 chambres à 700 m des belles plages de la Mata', 'Torrevieja: mooie appartementen met 2 slaapkamers op 700 meter van de prachtige stranden van La Mata', '', 'Cette nouvelle résidence est idéalement située à 700 m des superbes plages de la Mata, Torrevieja. A distance de marche, vous trouverez de nombreux commerces, restaurants, bars,... La résidence comptera au total 7 blocs. Le 1er bâtiment compte 50 appartements, tous avec 2 chambres, 2 salles de bains et une cuisine ouverte sur le living. Les penthouses disposent de 3 chambres et d''un solarium. Tous les appartements jouissent d''une belle terrasse orientée sud-est donnant sur les espaces verts avec piscines. Les appartements au rez-de-chaussée ont un jardin privé. A partir du 2ème étage, les appartements jouissent de belles vues sur mer. La résidence fermée est aménagée avec de beaux jardins tropicaux, deux piscines, une piscine et une aire de jeux pour enfants, un spa et un espace fitness. Prix: à partir de 285.000 ? hors frais Penthouses 3 chambres avec solarium: à partir de 540.000 ? hors frais Inclus dans le prix: -Place de parking Fin des travaux 1er bloc : avril 2025 - bloc 2: octobre 2026', 'Deze nieuwe residentie is ideaal gelegen op 700 m van de prachtige stranden van La Mata, Torrevieja. Op wandelafstand vindt u tal van winkels, restaurants, bars,... De residentie zal in totaal 7 blokken hebben. Het 1ste gebouw heeft 50 appartementen, allemaal met 2 slaapkamers, 2 badkamers en een open keuken naar de woonkamer. De penthouses hebben 3 slaapkamers en een solarium. Alle appartementen hebben een prachtig terras op het zuidoosten met uitzicht op de tuinen met zwembaden. De appartementen op de begane grond hebben een eigen tuin. De gated community is aangelegd met prachtige tropische tuinen, twee zwembaden, een kinderbad en een speeltuin, een spa en een fitnessruimte. Prijs: vanaf ? 285.000 exclusief kosten Penthouses met 3 slaapkamers en solarium: vanaf ? 540.000 exclusief kosten Inbegrepen in de prijs: -Parkeerplaats', '', 285000, 'torrevieja-superbes-appartements-2-chambres-a-700-m-des-belles-plages-de-la-mata', 'torrevieja-mooie-appartementen-met-2-slaapkamers-op-700-meter-van-de-prachtige-stranden-van-la-mata', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1781', 'San Fulgencio : belles maisons en 3 chambres', 'San Fulgencio: prachtige huizen met 3 slaapkamers', '', 'Ces jolies maisons se trouvent dans le village typique de San Fulgencio, à quelques kilomètres des superbes plages de Guardamar. Le complexe comptera au total 24 maisons. Les maisons sont agencées comme suit: Rez-de-chaussée: cuisine équipée ouverte sur le séjour avec baies vitrées vers la terrasse et la piscine privée, 1 chambre, 1 salle de bains et 1 WC séparé. 1er étage: 2 chambres chacune avec un accès à une terrasse et 1 salle de bains 2ème étage: solarium Prix: 345.000 ? hors frais Inclus dans le prix: -piscine privée', 'Deze mooie huizen zijn gelegen in het typische dorpje San Fulgencio, op enkele kilometers van de prachtige stranden van Guardamar. Dit modern nieuwbouwproject zal bestaan uit 24 woningen met 3 slaapkamers. De woningen zijn als volgt ingedeeld: Begane grond: ingerichte open keuken naar de woonkamer met openslaande deuren naar het terras en het privé zwembad, 1 slaapkamer, 1 badkamer en 1 apart toilet. 1ste verdieping: 2 slaapkamers met elk toegang tot een terras en 1 badkamer 2de verdieping: solarium Prijs: ? 345.000 exclusief kosten Inbegrepen in de prijs: - privé zwembad', '', 345000, 'san-fulgencio-belles-maisons-en-3-chambres', 'san-fulgencio-prachtige-huizen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1783', 'Punta prima: superbes appartements 3 chambres proches de la mer', 'Punta Prima: prachtige appartementen met 3 slaapkamers dicht bij de zee', '', 'Cette superbe résidence est idéalement située à Punta Prima, à 300 m de la plage, juste à côté du parc naturel de Lo Férris et de sa grande palmeraie, et à proximité de nombreux restaurants, bars et commerces. Le centre de Torrevieja se situe à 5 minutes en voiture. Vous jouirez depuis la plupart des terrasses de belles vues sur mer. Sur le solarium, la piscine à débordement, le jacuzzi ainsi que les espaces communs avec zone de détente vous offrent également de magnifiques vues à 360 % sur la mer et l?environnement. Les appartements disposent de 3 chambres et 2 de salles de bains, une place de parking et un débarras et une belle terrasse. Les appartements du rez-de-chaussée disposent également d''un jardin privé (avec possibilité de construire une piscine privée moyennant supplément). Prix: à partir de 412.000 ? hors frais Fin des travaux: juin 2024', 'Deze prachtige residentie is ideaal gelegen in Punta Prima, op 300 m van het strand, direct naast het natuurpark Lo Férris en zijn grote palmentuin, en dichtbij vele restaurants, bars en winkels. Het centrum van Torrevieja ligt op 5 minuten rijden met de auto. Vanaf de meeste terrassen kunt u genieten van een prachtig uitzicht op zee. Op het solarium bieden het zwembad, de jacuzzi en de gemeenschappelijke ruimtes met ontspanningsruimte u ook een prachtig 360% uitzicht op de zee en de omgeving. De appartementen hebben 3 slaapkamers en 2 badkamers, een parkeerplaats en een berging en een leuk terras. De appartementen op de begane grond hebben ook een privétuin (met de mogelijkheid om tegen meerprijs een privézwembad aan te leggen). Prijs: vanaf ? 412.000 exclusief kosten Oplevering: juni 2024', '', 412000, 'punta-prima-superbes-appartements-3-chambres-proches-de-la-mer', 'punta-prima-prachtige-appartementen-met-3-slaapkamers-dicht-bij-de-zee', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1785', 'Benijofar: beaux appartements 2 chambres', 'Benijofar: prachtige appartementen met 2 slaapkamers', '', 'Cette nouvelle résidence est idéalement située à Bénijofar, à proximité de nombreux commerces et à seulement 10 minutes en voiture des superbes plages de Guardamar. Les amateurs de golf trouveront également leur bonheur avec de nombreux parcours situés aux alentours. La résidence comptera au total 21 appartements 2 ou 3 chambres. Les appartements 2 chambres disposent de 2 salles de bains et de belles terrasses ou un solarium pour les appartements du 2ème étage. Belle piscine commune entourée de magnifiques jardins. Prix: de 249.000 ? à 294.000 ? hors frais Livraison: fin 2023', 'Deze nieuwe residentie is ideaal gelegen in Bénijofar, dichtbij winkels en op slechts 10 minuten rijden van de prachtige stranden van Guardamar. Golfliefhebbers zullen ook hun geluk vinden op de golfterreinen in de omgeving. De residentie zal in totaal 21 appartementen hebben met 2 of 3 slaapkamers en 2 badkamers, met grote terrassen of solarium voor de appartementen op de 2de verdieping. Mooi gemeenschappelijk zwembad omgeven door prachtige tuinen. Prijs: van ? 249.000 tot ? 294.000 exclusief kosten Oplevering: eind 2023', '', 249000, 'benijofar-beaux-appartements-2-chambres', 'benijofar-prachtige-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1877', 'DERNIERES UNITES! San Miguel de Salinas: beaux appartements modernes en 3 chambres', '', '', 'Nouvelle résidence située au calme à San Miguel de Salinas, à distance de marche de toutes les commodités (cafés, restaurants, supermarchés,...) et à 15 minutes des plages de Torrevieja ou de Campoamor. La résidence propose des appartements 2 ou 3 chambres, avec 2 salles de bains. Les appartements situés au rez-de-chaussée disposent d''une terrasse et d''un jardin, les appartements du 1er étage jouissent d''un spacieux solarium. Les zones communes compteront de belles zones vertes ainsi que deux piscines communes. Prix: à partir de 249.900 ? hors frais Fin des travaux: Phase 1: septembre 2025 Phase 2: février 2026', '', '', 249900, 'dernieres-unites-san-miguel-de-salinas-beaux-appartements-modernes-en-3-chambres', '', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1788', 'Lomas de Cabo Roig: superbes appartements 3 chambres', 'Lomas de Cabo Roig: prachtige appartementen met 3 slaapkamers', '', 'Cette nouvelle résidence est située au calme à Lomas de Cabo Roig, à distance de marche de deux centres commerciaux avec nombreux restaurants, bars et magasins. La résidence comptera au total 24 appartements 2 ou 3 chambres. Les appartements comptent 3 chambres, 2 salles de bains et une belle terrasse. Les penthouses du dernier étage disposent également d''un solarium. Belle piscine commune avec pataugeoire, jacuzzi, fitness et zone de barbecue. Prix: à partir de 369.800 ? hors frais Pas de penthouses 3 chambres disponibles Inclus: place de parking et remise, climatisation, électroménagers, chauffage au sol dans les salles de bains Fin des travaux: décembre 2024', 'Deze nieuwe residentie is rustig gelegen in Lomas de Cabo Roig, op wandelafstand van twee winkelcentra met een uitgebreid aanbod aan restaurants, bars en winkels. De residentie zal bestaan uit 24 appartementen met 2 of 3 slaapkamers. De appartementen hebben 3 slaapkamers, 2 badkamers en een mooi terras. De penthouses op de bovenste verdieping hebben ook een solarium. Prachtig gemeenschappelijk zwembad met kindergedeelte, jacuzzi, fitness en barbecue zone. Prijs: vanaf ? 369.0000,- exclusief kosten Er zijn geen penthouses beschikbaar in 3 slaapkamers Inbegrepen: parkeerplaats en berging, airconditioning, elektrische apparaten, vloerverwarming in de badkamers. Oplevering: december 2024', '', 369800, 'lomas-de-cabo-roig-superbes-appartements-3-chambres', 'lomas-de-cabo-roig-prachtige-appartementen-met-3-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1790', 'San Miguel de Salinas: appartements 2 chambres très modernes', 'San Miguel de Salinas: zeer moderne appartementen met 2 slaapkamers', '', 'Ces superbes appartements sont situés à San Miguel de Salinas, à proximité de toutes les commodités et à 15 minutes des plages de Torrevieja ou de Campoamor et du centre commercial ''Zenia Boulevard''. Dans les environs immédiats, vous trouverez également de nombreux parcours de golf (Villamartin, Las Colinas, Las Ramblas,...). La résidence, au design très moderne, propose des appartements 2 ou 3 chambres. Les appartements 2 chambres disposent de 2 salles de bains, d''une cuisine ouverte donnant sur le living avec baies vitrées vers la belle terrasse (de minimum 26 m²). Certains appartements du rez-de-chaussée jouissent également d''un jardin. Belle zone commune avec grande piscine et jardins. Prix: à partir de 234.900? hors frais Possibilité d''acheter une cave, à partir de 3.900 ? HF Remise des clés: avril 2026 ou septembre 2026', 'Deze prachtige appartementen zijn gelegen in San Miguel de Salinas, dicht bij alle voorzieningen en op 15 minuten van de stranden van Torrevieja of Campoamor en het winkelcentrum ''Zenia Boulevard''. In de directe omgeving vindt u ook tal van golfbanen (Villamartin, Las Colinas, Las Ramblas,...). De residentie, met een zeer modern design, heeft zeer lichte appartementen met 2 of 3 slaapkamers. De appartementen met 2 slaapkamers hebben 2 badkamers, een open keuken naar de woonkamer met openslaande deuren naar het prachtige terras (minimaal 26 m²). Sommige appartementen op de begane grond hebben ook een tuin. Mooie gemeenschappelijke zone met groot zwembad en tuinen. Prijs: vanaf ?234.900 exclusief kosten Oplevering: april 2026 of sept 2026', '', 234900, 'san-miguel-de-salinas-appartements-2-chambres-tres-modernes', 'san-miguel-de-salinas-zeer-moderne-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false),
('SEC-1791', 'NOUVELLE PHASE EN FRONT DE MER! San Juan de los Terreros: beaux appartements 2 chambres', 'NIEUWE FASE AAN DE KUST! San Juan de los Terreros: prachtige appartementen met 2 slaapkamers', '', 'Belle résidence de style Andalou, parfaitement intégrée dans le paysage et située dans un environnement exceptionnel: à quelques pas de la mer, à proximité du village de San Juan de los Terreros et à seulement 10 min de la ville d''Aguilas. Tout proche de la résidence, vous trouverez un centre commercial avec épicerie, plusieurs restaurants et petits commerces. La résidence dispose de 2 belles piscines, dont une face à la mer, ainsi que de 2 jacuzzis. Les appartements comptent 2 chambres et 1 ou 2 salles de bains, une buanderie, et une cuisine ouverte donnant sur le living avec portes-fenêtres vers la terrasse. Les appartements du rez-de-chaussée ont une grande terrasse avec beau jardin privé, les appartements du 1er étage disposent d''une terrasse et d''un vaste solarium. Parking souterrain inclus dans le prix. Prix: 2 chambres au rez-de-chaussée: à partir de 227.000 ? hors frais 2 chambres au 1er étage: à partir de 255.000 ? hors frais. Appartement front de mer: à partir de 381.000 ? hors frais Remise des clés: key ready ou décembre 2025', 'Mooie residentie in Andalusische stijl, perfect geïntegreerd in het landschap en gelegen in een uitzonderlijke omgeving: op een steenworp afstand van de zee, vlakbij het dorp San Juan de los Terreros en op slechts 10 minuten van de stad Aguilas. Zeer dicht bij de residentie vindt u een winkelcentrum met een kruidenierswinkel, diverse restaurants en kleine winkeltjes. De residentie heeft 2 prachtige zwembaden, waarvan er één uitkijkt op zee, evenals 2 jacuzzi''s. De appartementen hebben 2 slaapkamers en 1 of 2 badkamers, een wasruimte en een open keuken naar de woonkamer met openslaande deuren naar het terras. De appartementen op de begane grond hebben een groot terras met een prachtige privétuin, de appartementen op de 1e verdieping hebben een terras en een groot solarium. Ondergrondse parkeerplaats inbegrepen in de prijs. Prijs: 2 slaapkamers op de begane grond: vanaf ? 227.000 exclusief kosten 2 slaapkamers op de 1e verdieping: vanaf ? 255.000 exclusief kosten. Appartement aan zee: vanaf ? 381.000 exclusief kosten Oplevering: key ready ou décembre 2025', '', 227000, 'nouvelle-phase-en-front-de-mer-san-juan-de-los-terreros-beaux-appartements-2-chambres', 'nieuwe-fase-aan-de-kust-san-juan-de-los-terreros-prachtige-appartementen-met-2-slaapkamers', '', 0, 0, 0, 0, 'appartement', 'bon_etat', 'disponible', '', '', '', '{}', '', false)
